import{m as t,aU as l,z as o,M as i}from"./chunks/framework.LN92DB6A.js";const r=JSON.parse('{"title":"广州居住证办理攻略：条件、材料、流程一次讲清","description":"来广州打拼，居住证是享受公共服务的基础。本文从居住登记到申领签注，全流程讲清广州居住证怎么办。","frontmatter":{"title":"广州居住证办理攻略：条件、材料、流程一次讲清","tags":["广州","居住证","居住登记","粤省事","异地办理"],"categories":["生活指南"],"date":"2026-05-28T00:00:00.000Z","description":"来广州打拼，居住证是享受公共服务的基础。本文从居住登记到申领签注，全流程讲清广州居住证怎么办。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/residence-permit"}]]},"headers":[],"relativePath":"posts/2026/residence-permit.md","filePath":"posts/2026/residence-permit.md","lastUpdated":1779868425000}');const a=t({name:"posts/2026/residence-permit.md"},[["render",function(t,r,a,s,n,e){return l(),o("div",null,[...r[0]||(r[0]=[i('<p>来广州工作生活，居住证可能是你最先需要办的证件之一。小孩上学、考驾照、办港澳签注、积分入户，样样都离不开它。很多人以为很麻烦，其实搞清楚流程后并不复杂。</p><p>简单说：<strong>先做居住登记 → 登记满半年 → 申领居住证 → 每年签注一次。</strong></p><h2 id="办理条件" tabindex="-1">办理条件 <a class="header-anchor" href="#办理条件" aria-label="Permalink to &quot;办理条件&quot;">​</a></h2><p>在广州申领居住证，需要同时满足：</p><ul><li>在广州<strong>居住半年以上</strong>（从居住登记之日起算）</li><li>符合以下条件之一： <ul><li><strong>合法稳定就业</strong>（有劳动合同或营业执照）</li><li><strong>合法稳定住所</strong>（租房、自购房、住单位宿舍等）</li><li><strong>连续就读</strong>（在广州学校就读）</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>居住登记满半年是硬性前提，没有捷径。来广州后尽早去登记，别等到要用居住证了才想起来。</p></div><h2 id="第一步-居住登记" tabindex="-1">第一步：居住登记 <a class="header-anchor" href="#第一步-居住登记" aria-label="Permalink to &quot;第一步：居住登记&quot;">​</a></h2><p>来广州后，尽快到居住地所在的<strong>社区服务中心</strong>或<strong>出租屋管理处</strong>办理居住登记。</p><h3 id="所需材料" tabindex="-1">所需材料 <a class="header-anchor" href="#所需材料" aria-label="Permalink to &quot;所需材料&quot;">​</a></h3><ul><li>本人<strong>身份证</strong>原件</li><li><strong>居住地址证明</strong>： <ul><li>租房：租赁合同 + 房东身份证复印件（部分街道需要房东到场或签署同意书）</li><li>自住：房产证或购房合同</li><li>单位宿舍：单位出具的住宿证明</li><li>亲友家：房主的房产证 + 亲友身份证 + 借住声明</li></ul></li></ul><h3 id="登记方式" tabindex="-1">登记方式 <a class="header-anchor" href="#登记方式" aria-label="Permalink to &quot;登记方式&quot;">​</a></h3><ul><li><strong>线下</strong>：到居住地街道办/社区服务中心窗口办理</li><li><strong>线上</strong>：通过&quot;粤省事&quot;小程序 → 搜索&quot;居住登记&quot; → 按提示提交材料</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>居住登记需要房东配合。如果房东不配合办理租赁备案，可以先做居住登记（部分街道支持承诺制），但后续可能影响居住证申领。租房前跟房东确认好这一点。</p></div><h2 id="第二步-申领居住证" tabindex="-1">第二步：申领居住证 <a class="header-anchor" href="#第二步-申领居住证" aria-label="Permalink to &quot;第二步：申领居住证&quot;">​</a></h2><p>居住登记满<strong>6个月</strong>后，就可以申领居住证了。</p><h3 id="线上办理-推荐" tabindex="-1">线上办理（推荐） <a class="header-anchor" href="#线上办理-推荐" aria-label="Permalink to &quot;线上办理（推荐）&quot;">​</a></h3><ol><li>打开微信搜索**&quot;粤省事&quot;**小程序</li><li>搜索&quot;<strong>居住证申领</strong>&quot;</li><li>按提示填写个人信息、上传材料</li><li>提交后等待审核</li><li>审核通过后可选择<strong>邮寄到家</strong>或到窗口自取</li></ol><h3 id="线下办理" tabindex="-1">线下办理 <a class="header-anchor" href="#线下办理" aria-label="Permalink to &quot;线下办理&quot;">​</a></h3><ol><li>到居住地所在的<strong>街道办</strong>或<strong>派出所</strong>户籍窗口</li><li>取号排队</li><li>提交材料，工作人员现场审核</li><li>审核通过后按通知时间领取</li></ol><h3 id="所需材料-1" tabindex="-1">所需材料 <a class="header-anchor" href="#所需材料-1" aria-label="Permalink to &quot;所需材料&quot;">​</a></h3><ul><li><strong>身份证</strong>原件</li><li><strong>居住证照片回执</strong>（可在&quot;粤易拍&quot;线上办理，或到照相馆拍）</li><li><strong>居住地址证明</strong>（租赁合同/房产证/单位证明等）</li><li><strong>就业证明</strong>（劳动合同/营业执照）或<strong>就读证明</strong>（学生证/在读证明）</li></ul><h2 id="签注与续期" tabindex="-1">签注与续期 <a class="header-anchor" href="#签注与续期" aria-label="Permalink to &quot;签注与续期&quot;">​</a></h2><p>居住证<strong>每年签注一次</strong>，有效期为一年。</p><ul><li>在到期前<strong>30天内</strong>办理签注</li><li>签注条件不变：仍在广州居住且符合就业/住所/就读条件</li><li>可通过&quot;粤省事&quot;线上签注，或到街道办窗口办理</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>逾期未签注的居住证功能会被中止。补办签注后功能恢复，但中间断档期间可能影响积分入户年限计算。记得设个闹钟提醒自己！</p></div><h2 id="居住证有什么用" tabindex="-1">居住证有什么用 <a class="header-anchor" href="#居住证有什么用" aria-label="Permalink to &quot;居住证有什么用&quot;">​</a></h2><p>别小看这张证，它的用途比你想象的多：</p><ul><li><strong>积分入户/积分入学</strong>：居住证年限是重要加分项</li><li><strong>小孩上学</strong>：非户籍生入学需要父母持有有效居住证</li><li><strong>办港澳签注</strong>：非广州户籍在穗办理港澳签注需要居住证</li><li><strong>考驾照</strong>：异地在穗考驾照需要居住证</li><li><strong>机动车登记</strong>：在穗上牌需要居住证</li><li><strong>申请公租房</strong>：需要居住证满一定年限</li><li><strong>婚姻登记</strong>：异地在穗登记结婚需要居住证</li></ul><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>居住登记要趁早</strong>：来广州第一件事就是去登记，别等到要用证了才发现差半年</li><li><strong>房东不配合怎么办</strong>：可以跟房东协商，或找社区工作站咨询替代方案。实在不行，换房时优先选愿意配合的房东</li><li><strong>换区居住需要重新登记</strong>：从天河搬到番禺，需要到新居住地重新做居住登记，但之前的居住年限可以累计</li><li><strong>电子居住证和实体证等效</strong>：粤省事上可以查看电子居住证，和实体证具有同等法律效力</li><li><strong>照片回执线上办就行</strong>：用&quot;粤易拍&quot;小程序，在家拍照上传就能拿到回执号，不用跑照相馆</li><li><strong>居住证工本费</strong>：首次申领免费，补领/换领收取工本费20元</li></ul><p>在广州生活，居住证是最基础也最重要的证件之一。早点登记、按时签注，后面办什么事都方便。</p>',31)])])}]]);export{r as __pageData,a as default};
